"""
MKT Original Commentary — Genesis chapters 31–32
Run: python3 scripts/zc-original-genesis-31-32.py

Source data used:
- data/interlinear/genesis.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/genesis.json (MKT text)

Key decisions:
- Ch 31: פַּחַד יִצְחָק (v42, 53 — "Fear/Dread of Isaac") is one of the most
  unusual divine epithets in the OT; the commentary treats it as an authentic
  archaic epithet, not a mistake; the meaning is "the God before whom Isaac
  stands in awe/dread" — an epithet from the experience of theophany
- The teraphim (v19): Rachel's theft is noted; the Nuzi tablet connection
  (household god possession as inheritance claim) is mentioned as contextual
  background but the text itself does not explain Rachel's motivation
- Ch 31 bilingualism (v47): Laban names the heap in Aramaic, Jacob in Hebrew;
  this is the only bilingual place-name episode in the Torah; the different
  languages mark a real cultural-linguistic boundary
- Jabbok / Jacob / wrestle (ch 32 vv. 22-24): the triple wordplay יבק / יעקב /
  אבק is noted as a deliberate narrative feature
- The identity of the wrestler (32:24): identified only retroactively by
  Jacob's own interpretation (v30: "I have seen God face to face"); the
  narrative uses ʾîš (man) throughout — the commentary preserves this
  deliberate ambiguity rather than flattening it to "angel" (as Hos 12:4 does)
  or "God" (as Jacob's confession does); both readings are in the text
- 32:28 etymology of Israel: כִּי-שָׂרִיתָ (you have striven) + אֵל (God) =
  "one who strives with God" — the Qal of שָׂרָה (to persist, strive, exert
  power); the passive reading "God strives" is possible but less likely given
  the clause structure wayyûḵal (and he prevailed, with Jacob as subject)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

GENESIS = {
  "31": {
    "1": '<p><strong>לָקַח יַעֲקֹב אֵת כָּל-אֲשֶׁר לְאָבִינוּ</strong> — "Jacob has taken everything belonging to our father." The verb <em>lāqaḥ</em> (to take) — used here accusatorially; Laban\'s sons describe Jacob\'s legitimate wage-earnings as a taking/seizure. <strong>וּמֵאֲשֶׁר לְאָבִינוּ עָשָׂה אֵת כָּל-הַכָּבֹד הַזֶּה</strong> (and from what belonged to our father he has made all this wealth) — <em>kāḇôḏ</em> (wealth, honor, glory — the root meaning is "heaviness"; wealth is what weighs heavily; cf. 13:2 where Abram is described as "heavy/wealthy" in cattle, silver, and gold). The sons perceive Jacob\'s prosperity as their loss — a zero-sum view of wealth that is explicitly corrected in v. 9: God, not Jacob, transferred the livestock.</p>',
    "2": '<p><strong>פְּנֵי לָבָן</strong> (<em>pĕnê lāḇān</em>, the face of Laban) — "Jacob saw that Laban\'s face was not with him as before." <em>Pānîm</em> (face) is the chapter\'s primary perceptual-relational indicator: one reads the face of another to determine their attitude, goodwill, or hostility. The "face" idiom runs through vv. 2 and 5: Jacob reads Laban\'s face and sees the changed relationship. The same face-vocabulary appeared in 32:20 and 33:10 (seeing Jacob\'s face is like seeing the face of God) and will appear at the Peniel encounter in 32:30. The OT uses "face" as a synecdoche for the entire relational stance of a person.</p>',
    "3": '<p><strong>וַיֹּאמֶר יְהוָה אֶל-יַעֲקֹב שׁוּב אֶל-אֶרֶץ אֲבוֹתֶיךָ</strong> — "the LORD said to Jacob: return to the land of your fathers." <em>Šûḇ</em> (to return, turn back) — the verb of covenantal return; the same word used for moral repentance (Isa 55:7; Jer 3:12-14) carries a more literal sense here: physically return to the covenant land. <em>Wĕʾel-môlaḏtĕḵā</em> (and to your birthplace) — the same word as 12:1 where Abraham was told to leave his <em>môlaḏāh</em>; here Jacob is commanded to return to Abraham\'s <em>môlaḏāh</em>. <strong>וְאֶהְיֶה עִמָּךְ</strong> (and I will be with you) — the divine presence promise of 28:15 ("I am with you and will watch over you") is repeated as the warrant for the return; YHWH\'s presence is portable, not confined to Bethel or to Canaan.</p>',
    "4": '<p>Jacob summons Rachel and Leah to the field — away from Laban\'s household — to speak privately. The location (field, away from the house) is tactically chosen: Jacob knows the domestic space is surveilled by Laban\'s household; he chooses the open field where his flocks are, his domain, for the family council. The summoning of both wives together for a joint decision is notable — Jacob treats them as equal partners in the decision to flee, though the decision has already been divinely mandated (v. 3).</p>',
    "5": '<p><strong>פְּנֵי אֲבִיכֶן אֵינֶנּוּ אֵלַי כִּתְמֹל שִׁלְשׁוֹם</strong> — "your father\'s face is not toward me as yesterday and the day before." The idiom <em>kitmōl šilšôm</em> (as yesterday and the day before) = formerly, previously; the standard Hebrew expression for a prior established state. Jacob reads Laban\'s face (v. 2) and now articulates it to Rachel and Leah: the relational warmth has ended. <strong>וֵאלֹהֵי אָבִי הָיָה עִמָּדִי</strong> (but the God of my father has been with me) — the contrast: Laban\'s face has changed, but God\'s faithfulness has not. The "God of my father" (<em>ʾĔlōhê ʾāḇî</em>) becomes Jacob\'s standard divine reference throughout this chapter (vv. 5, 29, 42, 53).</p>',
    "6": '<p><strong>בְּכָל-כֹּחִי עָבַדְתִּי אֶת-אֲבִיכֶן</strong> (<em>bĕḵol-kōḥî ʿāḇaḏtî ʾet-ʾăḇîḵen</em>) — "with all my strength I have served your father." <em>Kōaḥ</em> (strength, power, capacity) — Jacob claims maximal effort: not partial, not adequate, but total commitment. The legal context of this claim will appear in vv. 38-42 where Jacob defends his service record in detail. The witness to Rachel and Leah is important: he is establishing the factual record of his labor before the family audience.</p>',
    "7": '<p><strong>וַיַּחֲלֵף אֶת-מַשְׂכֻּרְתִּי עֲשֶׂרֶת מֹנִים</strong> (<em>wayyaḥălēp ʾet-maśkurtî ʿăśeret mônîm</em>) — "he changed my wages ten times." <em>Māśkōret</em> (wages, hire — from <em>śāḵar</em>, to hire; the payment due to a hired worker; cf. the teraphim-related hire in 30:18 where Leah "hired" Jacob for a night with the mandrakes). <em>ʿĂśeret mônîm</em> (ten times) — a round number expressing complete repetition of wrongdoing (cf. Num 14:22 where Israel tested YHWH "these ten times" — the idiom of maximal accumulative offense). <strong>וְלֹא-נְתָנוֹ אֱלֹהִים לְהָרַע עִמָּדִי</strong> (but God did not allow him to harm me) — the theological interpretation: Laban\'s serial wage-changes were overridden by divine protection. Jacob\'s account gives God the agency in his prosperity, not his own cleverness with the breeding rods (30:37-42).</p>',
    "8": '<p>Jacob explains the mechanism of God\'s overriding of Laban\'s wage manipulations: whenever Laban specified "speckled as your wages," all the animals bore speckled young; whenever "streaked," all bore streaked. The narrative here revises the ch. 30 account (where Jacob seemed to use selective breeding techniques with rods) by attributing the outcome to divine action. The dream-revelation in vv. 10-12 gives Jacob the divine perspective: God showed him the mechanism. The two accounts are complementary, not contradictory: Jacob used the rods; God overrode the natural odds to produce the contracted pattern.</p>',
    "9": '<p><strong>וַיַּצֵּל אֱלֹהִים אֶת-מִקְנֵה אֲבִיכֶם וַיִּתֶּן-לִי</strong> — "God has taken away your father\'s livestock and given it to me." <em>Hiṣṣîl</em> (Hiphil of <em>nāṣal</em>, to deliver, rescue, strip away) — the same verb used for deliverance from slavery and from enemies (Exod 3:8; 18:9-10; Judg 6:9). God "strips away" Laban\'s livestock and transfers them to Jacob: the language of divine deliverance applied to an economic reallocation. The theological claim is significant: Jacob\'s wealth is not the result of his skill or Laban\'s generosity but divine redistribution.</p>',
    "10": '<p><strong>בְּעֵת יַחֵם הַצֹּאן</strong> (<em>bĕʿēt yaḥem haṣṣōʾn</em>) — "in the breeding season of the flock." <em>Yāḥam</em> (to be in heat, to warm — the verb for sexual arousal/readiness in animals; used for the male goats coming to mate; cf. Jer 2:24 for the same verb). Jacob\'s dream occurs at the moment of maximum biological activity — the breeding season — which is precisely when the selective breeding of ch. 30 was employed. The dream at the breeding season contextualizes the revelation: God reveals his management of the very moment Jacob thought he was managing.</p>',
    "11": '<p><strong>מַלְאַךְ הָאֱלֹהִים</strong> (<em>malʾaḵ hāʾĔlōhîm</em>, angel of God) — the divine messenger speaks to Jacob in the dream. The identification is the same as the messenger who appeared to Hagar (16:7; 21:17), who stopped Abraham at the Akedah (22:11-15), and who will accompany the Exodus (Exod 23:20). In the immediately following divine speech (v. 13), the messenger shifts from third-person divine speech to first-person self-identification ("I am the God of Bethel") — the angel and YHWH blur in the theophanic pattern of Genesis. <em>Hinnēnî</em> — Jacob\'s response (here I am, ready) — the covenant-readiness formula of Abraham (22:1, 7, 11) and Isaiah (6:8) is now Jacob\'s.</p>',
    "12": '<p><strong>כִּי רָאִיתִי אֵת כָּל-אֲשֶׁר לָבָן עֹשֶׂה לָּךְ</strong> — "for I have seen all that Laban has been doing to you." <em>Rāʾîtî</em> (I have seen) — the divine seeing that precedes divine action (cf. 29:32 where YHWH "sees" Leah\'s affliction; 16:13 where Hagar names the God who sees; 31:42 where God has "seen" Jacob\'s hardship). The divine declaration of having seen is the warrant for the command to return: God has observed the injustice and is now acting to rectify it. The vision reveals the ram patterns as a divine sign, not merely a natural occurrence managed by Jacob\'s rods.</p>',
    "13": '<p><strong>אָנֹכִי הָאֵל בֵּית-אֵל</strong> (<em>ʾānōḵî hāʾēl bêt-ʾēl</em>) — "I am the God of Bethel." An unusual divine self-identification: YHWH/the angel identifies himself not by covenant relationship ("God of Abraham, God of Isaac") but by a specific place and event — the Bethel theophany of 28:10-22. The identification links back to Jacob\'s dream at Bethel (the pillar, the oil, the vow) and confirms that the God who met Jacob at that night is the same God now commanding his return. <em>ʾĂšer māšaḥtā šām maṣṣēḇāh</em> (where you anointed the pillar) — the specific act (anointing the pillar with oil, 28:18) is cited as the identifying event. <strong>ʾĂšer nāḏartā lî šām neḏer</strong> (where you made me a vow there) — the Bethel vow (28:20-22) is now being called in: Jacob vowed; God kept his end (provision, protection, return); now the vow\'s condition is fulfilled and Jacob must return to the God who met him at Bethel.</p>',
    "14": '<p><strong>הַעוֹד לָנוּ חֵלֶק וְנַחֲלָה בְּבֵית אָבִינוּ</strong> — "do we still have any share and inheritance in our father\'s house?" <em>Ḥēleq</em> (portion, share) and <em>naḥălāh</em> (inheritance, inherited possession) — the legal inheritance vocabulary of the OT. Leah and Rachel are raising the question of their own disinheritance: have they been treated as heirs by their father or as commodities? The question is rhetorical — they already know the answer (v. 15: he has treated them as foreigners).</p>',
    "15": '<p><strong>הֲלוֹא נָכְרִיּוֹת נֶחְשַׁבְנוּ לוֹ</strong> (<em>hălōʾ nāḵriyyôt neḥšaḇnû lô</em>) — "have we not been regarded as foreigners by him?" <em>Nāḵriyyāh</em> (foreign woman, outsider — feminine of <em>nāḵrî</em>, foreign, alien, stranger; same root as <em>hikkîr</em>, to recognize — the outsider is the one not recognized). The daughters of Laban have been treated as non-family by their own father: <em>kî-ḵāhāh môḵerānû wayyōḵal gam-ʾāḵôl ʾet-kasĕpēnû</em> (he has sold us and even used up the bride-price paid for us) — the bride-price (<em>môhar</em>) should have gone to the bride\'s family and eventually to the bride herself; Laban consumed it, treating his daughters as sources of revenue rather than as family members with inheritance rights.</p>',
    "16": '<p><strong>וְעַתָּה כֹּל אֲשֶׁר אָמַר אֱלֹהִים אֵלֶיךָ עֲשֵׂה</strong> — "now, whatever God has told you, do it." Rachel and Leah align themselves completely with Jacob\'s divine mandate. Their endorsement is the family consensus that Jacob needed: the departure is not just divinely commanded but family-sanctioned. The wealth Jacob is taking belongs, they argue, to them and their children anyway (v. 16: "surely all the wealth God took from our father belongs to us and our children") — so there is no theft in the departure. The daughters\' theological alignment ("whatever God says") is their equivalent of the covenant-obedience formula.</p>',
    "17": '<p>Jacob acts: children and wives on camels, livestock ahead, goods packed. The departure sequence is rapid and comprehensive — the narrative lists the cargo categories to show that nothing is left behind. The movement is urgent: Rachel has already taken the teraphim (v. 19) and the departure must be completed before Laban returns from the sheep-shearing.</p>',
    "18": '<p><strong>מִקְנֵהוּ אֲשֶׁר רָכַשׁ</strong> (<em>miqnēhû ʾăšer rāḵaš</em>) — "his livestock that he had acquired." <em>Rāḵaš</em> (to acquire, accumulate — used for the accumulated wealth of Abraham in 12:5 and Esau in 36:6; a word for legally owned acquired property, not inherited). Jacob\'s departure with his legally acquired livestock parallels Abraham\'s departure from Egypt with his acquired wealth (12:16; 13:2) — both patriarchs depart enriched by foreign sojourn. <em>Paddān ʾărāmāh</em> (Paddan-Aram) → <em>ʾereṣ kĕnaʿan</em> (land of Canaan): the geographical movement is explicitly stated.</p>',
    "19": '<p><strong>וַתִּגְנֹב רָחֵל אֶת-הַתְּרָפִים אֲשֶׁר לְאָבִיהָ</strong> (<em>wattiḡnōḇ rāḥel ʾet-hattĕrāpîm ʾăšer lĕʾāḇîhā</em>) — "Rachel stole her father\'s household gods." <em>Gānaḇ</em> (to steal) — the same verb as Jacob "stealing" Laban\'s heart (v. 20) and Laban\'s accusation about the teraphim (v. 30). The verb creates a pattern of stealing: Rachel steals gods, Jacob steals the departure. <em>Tĕrāpîm</em> — household idols used in divination (1 Sam 15:23 links <em>tĕrāpîm</em> to divination; Ezek 21:21; Hos 3:4; Zech 10:2). Their function as potential inheritance-claim objects (Nuzi texts from the 15th-14th c. BCE indicate that possession of the paternal household gods could support an inheritance claim) may explain Rachel\'s motivation, though the text does not explicitly state it. The teraphim subplot creates narrative tension (Laban searches; Jacob unknowingly vows death on the thief, v. 32; Rachel hides them) that is resolved without resolution — the teraphim are never found or returned.</p>',
    "20": '<p><strong>וַיִּגְנֹב יַעֲקֹב אֶת-לֵב לָבָן הָאֲרַמִּי</strong> (<em>wayyiḡnōḇ yaʿăqōḇ ʾet-lēḇ lāḇān hāʾărammî</em>) — "Jacob stole the heart of Laban the Aramean." The idiom <em>gānaḇ lēḇ</em> (steal the heart) = to act without someone\'s knowledge, to deceive someone\'s mind: "he stole Laban\'s heart" by not telling him he was leaving. The verbal echo of v. 19 (<em>gānaḇ</em> for both Rachel\'s physical theft and Jacob\'s deceptive departure) is deliberate: both theft-acts occur simultaneously; the family\'s departure is a complex of taking (<em>lāqaḥ</em>) and stealing (<em>gānaḇ</em>). <em>ʿAl-bĕlî higgîḏ lô kî bōrēaḥ hûʾ</em> (by not telling him that he was fleeing) — <em>bāraḥ</em> (to flee, run away) — Jacob\'s departure is a flight, not a dignified leave-taking.</p>',
    "21": '<p><strong>וַיַּעֲבֹר אֶת-הַנָּהָר</strong> (<em>wayyaʿăḇōr ʾet-hannāhār</em>) — "he crossed the river." <em>ʿĀḇar</em> (to cross over, pass through) — the same verb for the crossing of the Euphrates that Abraham made in reverse at the beginning of the patriarchal narrative (the <em>ʿîḇrî</em>, "Hebrew," is "the one who crossed over"). Jacob crosses the Euphrates going the opposite direction from Abraham — he is returning from the origin-country to the covenant land. <em>Wayyāśem ʾet-pānāyw har haggīlʿāḏ</em> (he set his face toward the hill country of Gilead) — the idiom <em>śûm pānîm</em> (set the face) = to determine, resolve, fix one\'s direction; cf. Luke 9:51 where Jesus "set his face" toward Jerusalem.</p>',
    "22": '<p><strong>בַּיּוֹם הַשְּׁלִישִׁי</strong> (<em>bayyôm haššĕlîšî</em>) — "on the third day." The three-day gap between Jacob\'s departure and Laban\'s notification repeats the three-day structure of significant intervals in Genesis (22:4 — Abraham reaches Moriah on the third day). Laban learns of the departure three days after the fact — Jacob has a significant head start. The third-day structure here may be purely narrative (a realistic travel interval) or may carry the weight of the pattern of decisive action following a period of delay.</p>',
    "23": '<p><strong>וַיִּרְדֹּף אַחֲרָיו דֶּרֶךְ שִׁבְעַת יָמִים</strong> — "he pursued him for seven days." Laban pursues with his relatives for seven days — a full week of travel — to catch Jacob in the Gilead hills. The pursuit is overtly hostile: he takes his kinsmen, implying the threat of force. <em>Wayyaḏḇēq ʾōtô bĕhar haggīlʿāḏ</em> (he overtook him in the hill country of Gilead) — <em>dāḇaq</em> (to cling, stick, overtake — the same word for the covenant loyalty of Ruth 1:14 ["Ruth clung to her"]; here it describes hostile pursuit). Laban closes the gap; without the divine intervention of v. 24, the confrontation could be violent.</p>',
    "24": '<p><strong>פֶּן-תְּדַבֵּר עִם-יַעֲקֹב מִטּוֹב עַד-רָע</strong> (<em>pen-tĕdabbēr ʿim-yaʿăqōḇ miṭṭôḇ ʿaḏ-rāʿ</em>) — "lest you speak to Jacob from good to bad." The polar merism <em>miṭṭôḇ ʿaḏ-rāʿ</em> (from good to bad) = anything at all; a merism that comprehends the entire spectrum between two extremes (cf. 24:50: Laban said he could say "nothing to you good or bad"). The identical prohibition was given (in inverse form) for the treaty in 24:50; here it is a divine restriction on Laban. The warning is absolute: God forbids Laban from using any speech — favorable or unfavorable — to alter Jacob\'s course. The divine protection of Jacob\'s return is verbal as well as physical.</p>',
    "25": '<p>Laban overtakes Jacob in the Gilead hills; both parties camp. The confrontation is deferred by the overnight camp — the actual confrontation begins in vv. 26-42. The tent-setting (<em>ṭāpā ʾet-ʾōhŏlô</em>) marks territorial establishment: Laban sets up camp in Jacob\'s territory (the hill country where Jacob has fled). The spatial dynamic: Laban has pursued Jacob into Jacob\'s chosen refuge; Jacob cannot flee further. The confrontation is forced.</p>',
    "26": '<p><strong>מֶה עָשִׂיתָ וַתִּגְנֹב אֶת-לְבָבִי</strong> (<em>meh ʿāśîtā wattignōḇ ʾet-lĕḇāḇî</em>) — "what have you done? You have stolen my heart." Laban\'s accusation uses both the heart-stealing idiom (v. 20) and the captive-metaphor: <em>kišĕḇûyôt ḥāreḇ</em> (like captives taken by the sword). The sword-captive metaphor is hyperbolic — Jacob left peacefully with his family and livestock — but it expresses Laban\'s sense of violation: his daughters have been taken as if by force, without ceremony or farewell. <em>Lāmāh naḵaḇtā lāḇōraḥ</em> (why did you hide yourself in fleeing?) — <em>naḵāh</em> (to hide oneself, steal away) — Laban\'s complaint is about the secrecy, not about the departure itself.</p>',
    "27": '<p><strong>לָמָּה גָנַבְתָּ אֹתִי</strong> — "why did you steal away from me?" Laban\'s complaint about the theft of departure contrasts with what he says he would have done: send Jacob off with joy, song, timbrels (<em>tuppîm</em>), and harps (<em>kinnôr</em>). The festive-farewell vocabulary describes the opposite of a fugitive\'s midnight flight. Whether Laban would actually have done this (or used the occasion to prevent Jacob\'s departure) is not resolvable from the text; Jacob himself answers in v. 31 that he was afraid Laban would have taken his daughters by force.</p>',
    "28": '<p><strong>לֹא נְטַשְׁתַּנִי לְנַשֵּׁק לְבָנַי וְלִבְנֹתָי</strong> — "you did not allow me to kiss my grandchildren and my daughters." Laban\'s complaint shifts from legal accusation (theft) to relational grief: he was denied the farewell kiss. The kiss of blessing and farewell is a covenantal-relational gesture in the ANE (cf. 29:13 where Laban kissed Jacob at his arrival; 31:55 where he will kiss his grandchildren before departing). <em>Nāšaq</em> (to kiss) in the patriarchal narratives marks recognition, acceptance, and blessing-transfer. Laban claims relational injury as well as legal injury.</p>',
    "29": '<p><strong>יֶשׁ-לְאֵל יָדִי לַעֲשׂוֹת עִמָּכֶם רָע</strong> (<em>yĕš-lĕʾēl yāḏî laʿăśôt ʿimmāḵem rāʿ</em>) — "it is in my power to do you harm." The phrase <em>lĕʾēl yāḏî</em> (to my hand is El/power) — <em>ʾēl</em> here means "power, ability" rather than the divine name (though the orthography is identical); the idiom <em>yĕš lĕyāḏ</em> = "it is within one\'s ability/reach"; cf. Deut 28:32; Prov 3:27: "when it is in your power to do good." Laban explicitly acknowledges his restraint is God-imposed: the divine dream-warning (v. 24) is his reason for not using this power. The admission is a back-handed confession: God has overridden Laban\'s hostile capacity.</p>',
    "30": '<p><strong>לָמָּה גָנַבְתָּ אֶת-אֱלֹהָי</strong> (<em>lāmmāh gānaḇtā ʾet-ʾĕlōhāy</em>) — "why did you steal my gods?" Laban\'s final question in this speech is about the teraphim. The phrase <em>ʾĕlōhāy</em> (my gods) — Laban uses the possessive; these are his personal household deities, the objects of his religious practice. The irony that Jacob, the YHWH-worshipper, is accused of stealing Laban\'s gods (which he himself has called "my gods") is sharp: the narrative implicitly contrasts the portable, universal YHWH with Laban\'s localized household gods, which can be stolen and sat upon (v. 35).</p>',
    "31": '<p><strong>כִּי יָרֵאתִי</strong> (<em>kî yārēʾtî</em>, because I was afraid) — Jacob\'s one-word explanation for the secret departure: fear. The admission is honest and unsentimental. <em>Pen-tiḡzōl ʾet-bĕnōtêḵā mēʿimmāḏî</em> (lest you take your daughters from me by force) — <em>gāzal</em> (to seize by force, tear away — a word for violent seizure: Lev 19:13; Mic 2:2; Mal 1:13). Jacob\'s fear was that Laban would use force to end the marriage; given Laban\'s track record of deception (the Leah/Rachel substitution, the ten wage-changes), the fear is reasonable. The flight was driven by self-protective fear, not hostility.</p>',
    "32": '<p><strong>אֲשֶׁר תִּמְצָא אֶת-אֱלֹהֶיךָ לֹא יִחְיֶה</strong> (<em>ʾăšer timṣāʾ ʾet-ʾĕlōhêḵā lōʾ yiḥyeh</em>) — "whoever has your gods shall not live." Jacob\'s death-curse on the teraphim-thief is uttered without knowing Rachel is the thief. The dramatic irony is complete: the man who unknowingly pronounced a death-curse on his favorite wife will spend years grieving her death in childbirth (35:16-20). Whether the curse has any causal relationship to Rachel\'s death is theologically unresolved by the narrator; the connection is structural in the narrative. <em>Wĕlōʾ-yāḏaʿ yaʿăqōḇ kî rāḥēl gĕnāḇātam</em> (Jacob did not know that Rachel had stolen them) — the narrator\'s explicit note prevents the reader from blaming Jacob; he acts in good faith.</p>',
    "33": '<p>Laban\'s search: he goes through Jacob\'s tent, Leah\'s tent, and the tents of the two female servants (Bilhah and Zilpah) — a systematic, ordered search. The detail that Rachel\'s tent is searched last (after the others have been cleared) creates narrative suspense: will the teraphim be found? The order also reveals the household tent-arrangement: Jacob, Leah, servants, Rachel — the four household units.</p>',
    "34": '<p><strong>וְרָחֵל לָקְחָה אֶת-הַתְּרָפִים</strong> — Rachel has placed the teraphim inside the camel-saddle (<em>kār</em>, camel cushion/saddle-bag) and is sitting on them. <em>Wayyĕmaššēš lāḇān ʾet-kol-hāʾōhel wĕlōʾ māṣāʾ</em> (Laban searched the whole tent and did not find them) — the thorough but unsuccessful search. The household gods, objects of Laban\'s religious practice, are hidden under Rachel in a posture that renders them ritually unclean (menstruation, v. 35); the gods that were Laban\'s strength are powerless to reveal their location.</p>',
    "35": '<p><strong>כִּי-דֶרֶךְ נָשִׁים לִי</strong> (<em>kî-ḏereḵ nāšîm lî</em>) — "because the way of women is with me." The idiom <em>ḏereḵ nāšîm</em> (the way of women) is a euphemism for menstruation (cf. the only other OT occurrence in this idiom-sense). Rachel claims to be menstruating and therefore unable to rise — a socially and ritually compelling excuse in an ancient Near Eastern context where menstruation involved both social conventions of seclusion and ritual impurity concerns (Lev 15:19-30). The teraphim hidden under a menstruating woman are effectively hidden in a place no searching hand would go. Rachel\'s deception of her father mirrors Jacob\'s deception of his father in ch. 27 — the family talent for strategic misdirection is shared.</p>',
    "36": '<p><strong>וַיִּחַר לְיַעֲקֹב וַיָּרֶב בְּלָבָן</strong> (<em>wayyiḥar lĕyaʿăqōḇ wayyāreḇ bĕlāḇān</em>) — "Jacob was angry and argued with Laban." <em>Ḥārāh</em> (to burn, be hot — the idiom of anger: <em>ḥārāh ʾaph</em>, the anger burned); the anger here burns in Jacob after the failed search proves he has nothing to hide. <em>Rîḇ</em> (to contend, argue — the word for legal dispute: the same as the covenant dispute in Mic 6:1-2 "YHWH has a dispute [rîb] with his people"). Jacob\'s defense is a legal speech (vv. 36-42) that would be at home in a legal covenant dispute context: "what is my crime? What have I wronged you with?"</p>',
    "37": '<p><strong>שִׂים כֹּה נֶגֶד אַחַי וְאַחֶיךָ וְיוֹכִיחוּ בֵּין שְׁנֵינוּ</strong> — "put it here before my relatives and yours, and let them judge between the two of us." Jacob proposes public adjudication: lay out everything before the assembled relatives (Jacob\'s and Laban\'s) and let them serve as judges. The word <em>yôḵîḥû</em> (Hiphil of <em>yāḵaḥ</em> — to judge, adjudicate, decide) — the same root as the sign-prayer word in 24:14 (the servant asked God to <em>hôḵîaḥ</em>, designate, the right woman). Jacob\'s confident invitation to judgment expresses his consciousness of innocence on the theft charge.</p>',
    "38": '<p><strong>עֶשְׂרִים שָׁנָה אָנֹכִי עִמָּךְ</strong> (<em>ʿeśrîm šānāh ʾānōḵî ʿimmāḵ</em>) — "twenty years I have been with you." Jacob\'s formal defense begins with the chronological frame: twenty years (14 for the two daughters, 6 for the livestock, v. 41). <strong>רְחֵלֶיךָ וְעִזֶּיךָ לֹא שִׁכֵּלוּ</strong> (your ewes and female goats have not miscarried) — <em>šikkēl</em> (Piel of <em>šāḵal</em>, to be bereaved of children; in animals, to miscarry — the same root as the child-bereavement of 27:45 and Isa 49:21). The claim is that under Jacob\'s shepherding, the flocks reproduced perfectly: no miscarriages, no excess predation.</p>',
    "39": '<p><strong>טְרֵפָה לֹא-הֵבֵאתִי אֵלֶיךָ אָנֹכִי אֲחַטֶּנָּה</strong> — "I did not bring you what was torn by beasts; I bore the loss myself." The legal background: Exod 22:12-13 (later codified) specifies that if an animal in a shepherd\'s care is killed by a predator, the shepherd is released from liability if he shows the carcass; but if the animal is stolen, the shepherd must make restitution. Jacob claims to have gone beyond legal obligation: he covered even the losses from predation himself, absorbing costs that legally should have been Laban\'s. <strong>מִיָּדִי תְּבַקְשֶׁנָּה גְּנֻבְתִי יוֹם וּגְנֻבְתִי לָיְלָה</strong> (you held me responsible for whatever was stolen by day or night) — Jacob worked under a stricter standard than the law required.</p>',
    "40": '<p><strong>הָיִיתִי בַיּוֹם אֲכָלַנִי חֹרֶב</strong> (<em>hāyîtî ḇayyôm ʾăḵālanî ḥōreḇ</em>) — "by day the heat devoured me." <em>Ḥōreḇ</em> (scorching heat, drought — the same word as the sacred mountain Horeb; the dual meaning of the dry wilderness and the heat of the day). <em>Qeraḥ ballāylāh</em> (cold at night) — the temperature extremes of pastoral life in the Syro-Palestinian uplands: intense daytime heat and cold nights. <strong>וַתִּדַּד שְׁנָתִי מֵעֵינָי</strong> (sleep fled from my eyes) — <em>nāḏaḏ</em> (to flee, wander away — used for birds fleeing a nest, Prov 27:8; for fugitives, Isa 10:31; 21:14); here sleep is personified as something that has fled. The image of sleepless, temperature-abused labor is vivid and serves Jacob\'s legal argument.</p>',
    "41": '<p><strong>זֶה-לִּי עֶשְׂרִים שָׁנָה בְּבֵיתֶךָ</strong> — "these twenty years of mine in your house." The second statement of the twenty-year frame; Jacob now itemizes: fourteen years for the two daughters, six years for the flocks. <strong>וַתַּחֲלֵף אֶת-מַשְׂכֻּרְתִּי עֲשֶׂרֶת מֹנִים</strong> (and you changed my wages ten times) — the same phrase as v. 7; the repetition in the formal defense speech creates the rhetorical structure of a legal indictment: the wrong was repeated systematically, not once or accidentally. The twenty-year period and ten wage-changes form the factual core of Jacob\'s case against Laban.</p>',
    "42": '<p><strong>לוּלֵי אֱלֹהֵי אָבִי אֱלֹהֵי אַבְרָהָם וּפַחַד יִצְחָק הָיָה לִי</strong> — "if the God of my father, the God of Abraham and the <em>Paḥad</em> of Isaac, had not been with me." <em>Paḥad yiṣḥāq</em> (the Fear/Dread of Isaac, or the God whom Isaac fears) — one of the most unusual divine epithets in the OT; it appears only here and in v. 53. <em>Paḥad</em> (fear, dread, terror — the awesome reverence before YHWH; cf. Job 4:14; Ps 119:120; Isa 2:10, 19, 21 where God\'s presence produces this <em>paḥad</em>). The epithet names God from Isaac\'s subjective experience of theophanic encounter: the God Isaac knows through fear/awe at the revelations of his life (26:24-25; the Akedah\'s aftermath). <strong>כִּי-רָאָה אֱלֹהִים אֶת-עָנְיִי</strong> (because God has seen my affliction) — <em>ʿŏnî</em> (affliction, poverty, hardship) — the word used for Israel\'s bondage in Egypt (Exod 3:7: "I have seen the affliction of my people"). <em>Wayyôḵaḥ</em> (and he rebuked) — God\'s rebuke of Laban through the dream-warning was the decisive intervention that neutralized Laban\'s power.</p>',
    "43": '<p><strong>הַבָּנוֹת בְּנֹתַי וְהַבָּנִים בָּנַי</strong> — "the daughters are my daughters, the children are my children." Laban\'s response to Jacob\'s defense is not a legal counter-argument but a sweeping ownership claim: everything Jacob has is mine (<em>kōl ʾăšer-ʾattāh rōʾeh lî-hûʾ</em>, all that you see is mine). The claim is technically true from Laban\'s patriarchal perspective — daughters and their offspring belonged to the father\'s household. <strong>וְלִבְנֹתַי מָה-אֶעֱשֶׂה לָאֵלֶּה</strong> (what can I do today about my daughters?) — Laban shifts from possession-claim to helplessness; the rhetorical move acknowledges that the situation is irreversible. His verbal dominance (everything is mine) is immediately qualified by practical inability to change anything.</p>',
    "44": '<p><strong>וְעַתָּה לְכָה נִכְרְתָה בְרִית אֲנִי וָאָתָּה</strong> — "now come, let us cut a covenant, you and I." <em>Kārat bĕrît</em> (to cut a covenant) — the standard covenant-making formula (cf. 15:18; 21:27, 32; 26:28). Having failed to recover the teraphim and having been confronted by Jacob\'s effective defense, Laban proposes the only remaining option: a covenant that establishes a formal, enforceable boundary. The covenant is Laban\'s face-saving move: he cannot take his daughters back by force (v. 29: God has forbidden it), he cannot prove the teraphim theft (v. 34-35), and Jacob\'s labor defense is airtight (vv. 38-42); the covenant allows Laban to exit the confrontation with a structure he can live with.</p>',
    "45": '<p><strong>וַיִּקַּח יַעֲקֹב אֶבֶן וַיְרִימֶהָ מַצֵּבָה</strong> — "Jacob took a stone and set it up as a pillar." The standing stone (<em>maṣṣēḇāh</em>) — the same object Jacob erected at Bethel (28:18) for a different purpose: the Bethel pillar was a cultic memorial to theophany; this Galeed pillar is a legal boundary marker for a treaty. The stone serves as both witness and monument: <em>gal</em> (stone heap) + <em>ʿēḏ</em> (witness) = Galeed.</p>',
    "46": '<p>Jacob instructs his relatives to gather stones; they pile a heap. The heap is built by communal effort — different from the single standing stone Jacob set up (v. 45); the heap requires multiple people, making it a communal/collective monument. They eat beside the heap — the covenant meal that ratifies the treaty (cf. 26:30 where Isaac\'s covenant with Abimelech was ratified by eating and drinking; Exod 24:11 where the elders "ate and drank" before YHWH at Sinai).</p>',
    "47": '<p><strong>יְגַר שָׂהֲדוּתָא</strong> (<em>yĕḡar śāhăḏûtāʾ</em>, Jegar Sahadutha) — Laban\'s name in Aramaic: <em>yĕḡar</em> = heap (Aramaic; cf. Hebrew <em>gal</em>) + <em>śāhăḏûtāʾ</em> = of witness (Aramaic; cognate to Hebrew <em>ʿēḏût</em>). <strong>גַּלְעֵד</strong> (<em>galʿēḏ</em>, Galeed) — Jacob\'s Hebrew name: <em>gal</em> (heap) + <em>ʿēḏ</em> (witness). This is the only bilingual place-name episode in the Torah — the same place receives both an Aramaic and a Hebrew name that mean the same thing. The bilingualism marks the treaty boundary not just geographically but linguistically: Laban speaks Aramaic, Jacob speaks Hebrew; the two languages are the two cultures whose boundary this heap marks.</p>',
    "48": '<p><strong>הַגַּל הַזֶּה עֵד בֵּינִי וּבֵינְךָ הַיּוֹם</strong> — "this heap is a witness between me and you today." The heap is formally invested with legal witness-status — it will "see" future violations of the treaty. The use of a material object as a covenant witness is common in the OT (cf. Josh 24:27 where Joshua uses a stone as a witness; Isa 55:4 where David is named as a witness for the nations). <em>ʿAl-kēn qārāʾ-šĕmô galʿēḏ</em> — the Galeed name-explanation is repeated, anchoring it to the covenant-witness function.</p>',
    "49": '<p><strong>הַמִּצְפָּה אֲשֶׁר אָמַר יִצֶף יְהוָה בֵּינִי וּבֵינֶךָ</strong> — "and Mizpah, because he said: may YHWH watch between me and you." <em>Miṣpāh</em> (watchtower, lookout — from <em>ṣāpāh</em>, to look out, watch; <em>ṣōpeh</em> = watchman, sentinel). The place is named from the function YHWH is asked to perform: to watch (<em>yiṣep</em> = Qal imperfect of <em>ṣāpāh</em>) between the two parties when they are absent from each other. The Mizpah formula ("may YHWH watch between us") has become a Christian farewell blessing; in its original context it is a covenant-enforcement mechanism: YHWH is the unseen witness who oversees the treaty when no human witness is present. The connotation is not merely friendly watching but surveillance of potential violations.</p>',
    "50": '<p>The covenant\'s specific terms: no mistreatment of Laban\'s daughters and no additional wives. <strong>אִם-תְּעַנֶּה אֶת-בְּנֹתַי</strong> (if you mistreat my daughters) — <em>ʿānāh</em> (to afflict, oppress, humble) — the covenant protects Leah and Rachel from physical or domestic abuse. <strong>אִם-תִּקַּח נָשִׁים עַל-בְּנֹתַי</strong> (if you take wives besides my daughters) — the monogamy/family-limitation clause; Jacob already has four women (Leah, Rachel, Bilhah, Zilpah), but Laban forbids any additions. <em>ʾĒn ʾîš ʿimmānû rĕʾēh ʾĔlōhîm ʿēḏ bênî ûḇênêḵā</em> (though no one is with us, remember God is witness between me and you) — the appeal to divine witness precisely when no human witness is present: the covenant is operative beyond the reach of human surveillance.</p>',
    "51": '<p>Laban\'s formal statement of the boundary markers: the heap and the pillar. The heap was built communally (v. 46); the pillar was set by Jacob (v. 45). Both serve as witnesses; both are named in the treaty declaration. The formal enumeration of the witness objects matches ANE treaty-witness conventions where all witness parties (gods, natural objects, mountains) are named.</p>',
    "52": '<p><strong>עֵד הַגַּל הַזֶּה וְעֵדָה הַמַּצֵּבָה</strong> — "this heap is a witness and the pillar is a witness." The two-witness formula; in Israelite law two witnesses were required for legal validity (Deut 17:6; 19:15). The heap and the pillar together constitute the required pair of treaty witnesses. <em>ʾAm-lōʾ-ʾeʿĕḇōr... lĕrāʿāh</em> (I will not cross... to harm you) — the non-crossing-for-harm formula is mutual: both Laban and Jacob are bound not to cross the boundary with hostile intent. The treaty establishes a permanent territorial separation between the two family-nations.</p>',
    "53": '<p><strong>אֱלֹהֵי אַבְרָהָם וֵאלֹהֵי נָחוֹר יִשְׁפְּטוּ בֵינֵינוּ</strong> — "may the God of Abraham and the God of Nahor judge between us." The invocation uses a plural verb (<em>yišpĕṭû</em>, let them judge) with two divine referents — the God of Abraham and the God of Nahor — apparently treating them as separate divine entities (or as a plural of majesty/emphasis). Jacob\'s response corrects this: <strong>וַיִּשָּׁבַע יַעֲקֹב בְּפַחַד אָבִיו יִצְחָק</strong> (Jacob swore by the <em>Paḥad</em> of his father Isaac) — Jacob does not swear by the syncretic pairing Laban invokes but specifically by the God of his own covenant line, the <em>Paḥad</em> (Fear) of Isaac. The distinction marks a theological boundary: Laban\'s God of Nahor is not identified with YHWH; Jacob\'s oath is to YHWH alone, identified through the Isaac-epithet.</p>',
    "54": '<p><strong>וַיִּזְבַּח יַעֲקֹב זֶבַח בָּהָר</strong> (<em>wayyizbaḥ yaʿăqōḇ zebaḥ bāhār</em>) — "Jacob offered a sacrifice on the mountain." <em>Zebaḥ</em> (sacrificial meal-offering — a sacrifice of which the worshippers participate; the animal is slaughtered (<em>zāḇaḥ</em>) and then eaten communally; cf. the "peace offering" [<em>šĕlāmîm</em>] structure of Lev 3 where the meat is shared between altar, priests, and worshippers). The covenant is ratified through sacrifice and communal eating — the same pattern as 26:30 (Isaac-Abimelech covenant) and Exod 24:11 (Sinai covenant). They eat and spend the night.</p>',
    "55": '<p><strong>וַיַּשְׁכֵּם לָבָן בַּבֹּקֶר וַיְנַשֵּׁק לְבָנָיו וְלִבְנֹתָיו</strong> — "Laban rose early in the morning and kissed his grandchildren and daughters." The early morning rising (<em>hiškîm</em>, to rise at dawn — as Abraham in 22:3; 20:8) is here Laban\'s, not Jacob\'s: he wakes before the departure to kiss and bless (<em>wayyĕḇāreḵ</em>) his family. The final gesture is relational, not legal — blessing his daughters and grandchildren. <em>Wayyāšob limqōmô</em> (he returned to his place) — the covenant executed, Laban returns; the separation is permanent. The narrator closes the Laban episode without sentimentality: he went home. The twenty-years of relationship end with a morning blessing and a boundary heap.</p>'
  },
  "32": {
    "1": '<p><strong>וְיַעֲקֹב הָלַךְ לְדַרְכּוֹ</strong> (<em>wĕyaʿăqōḇ hālaḵ lĕḏarkô</em>) — "and Jacob went on his way." The phrase <em>lĕḏarkô</em> (on his way/road) — <em>derekh</em> (road, journey, way); the covenant word of the patriarchal narratives: the servant\'s journey in ch. 24 was the <em>derekh</em> YHWH prospered; the <em>derekh</em> Jacob vowed to keep safe in 28:20; now his return <em>derekh</em> begins. <strong>וַיִּפְגְּעוּ-בוֹ מַלְאֲכֵי אֱלֹהִים</strong> (and the angels of God met him) — <em>pāgaʿ</em> (to encounter, meet, fall upon — the same verb Jacob\'s servant used to describe providential meeting in 24:14; and the wrestling encounter verb in 32:25). The angels who met Jacob going into exile (28:12 — angels on the stairway) now meet him returning from exile.</p>',
    "2": '<p><strong>מַחֲנֵה אֱלֹהִים זֶה</strong> (<em>maḥănēh ʾĔlōhîm zeh</em>) — "this is the camp of God!" <em>Maḥăneh</em> (camp, encampment) — a military term for an armed force in camp; Jacob names the angelic assembly a divine military camp. <strong>וַיִּקְרָא שֵׁם-הַמָּקוֹם הַהוּא מַחֲנָיִם</strong> (he called that place Mahanaim) — <em>Maḥănāyim</em> = "two camps" (dual of <em>maḥăneh</em>). The dual name anticipates Jacob\'s own tactical division of his household into two camps (v. 7): the divine double-camp inspires the human double-camp strategy. Mahanaim will later become an important administrative center (2 Sam 2:8; 17:24; 1 Kgs 2:8).</p>',
    "3": '<p><strong>וַיִּשְׁלַח יַעֲקֹב מַלְאָכִים לְפָנָיו</strong> (<em>wayyišlaḥ yaʿăqōḇ malʾāḵîm lĕpānāyw</em>) — "Jacob sent messengers before him." The word <em>malʾāḵîm</em> (messengers, the same word as "angels") — Jacob sends his own human messengers (<em>malʾāḵîm</em>) to Esau just as God sent divine <em>malʾāḵîm</em> to Jacob (v. 1). The verbal echo is deliberate: Jacob, who has just encountered divine messengers, now sends his own. <em>ʾEl-ʾaḥîw ʿēśāw ʾarṣāh śēʿîr śĕḏeh ʾĔḏôm</em> (to his brother Esau in the land of Seir, the field of Edom) — the full geographical identification: Esau is in his territory (Seir/Edom, the land whose name connects to his redness and to the hairy goat, 25:25).</p>',
    "4": '<p><strong>כֹּה תֹאמְרוּן לַאדֹנִי לְעֵשָׂו</strong> (<em>kōh tōʾmĕrûn laʾḏōnî lĕʿēśāw</em>) — "thus you shall say to my lord Esau." Jacob addresses Esau as <em>ʾăḏōnî</em> (my lord) — the title of social superiority. This is the irony of the blessing: Jacob received the blessing that promised "be lord over your brothers" (27:29: <em>geḇîr lĕʾaḥêḵā</em>) and "may the sons of your mother bow down to you" — now Jacob himself uses the submission formula of <em>ʾăḏōnî</em> and calls himself "your servant Jacob" (<em>ʿaḇdĕḵā yaʿăqōḇ</em>). The covenant-heir approaches Esau in the language of a subordinate approaching a superior.</p>',
    "5": '<p>The message\'s content (v. 5): Jacob catalogues his wealth — cattle, donkeys, sheep, male and female servants — and says he is sending this message "that I may find favor in your eyes." <em>Limṣōʾ-ḥēn bĕʿênêḵā</em> (to find favor in your eyes) — the standard formula of petition to a superior (cf. Joseph finding favor, 39:4; Moses finding favor, Exod 33:12-13; Hannah, 1 Sam 1:18). Jacob is positioning himself as the subordinate seeking favor from Esau — the social reversal of the blessing scene is complete in Jacob\'s own self-presentation.</p>',
    "6": '<p><strong>גַּם הֹלֵךְ לִקְרָאתְךָ וְאַרְבַּע-מֵאוֹת אִישׁ עִמּוֹ</strong> — "and also he is coming to meet you, and four hundred men are with him." Four hundred men — a significant military force; the same number appears in 1 Sam 22:2 (David\'s initial militia at the cave of Adullam); and in 1 Sam 25:13 (David\'s force against Nabal). The number signals a prepared, organized military contingent — Esau is coming with what appears to be a war party. Jacob\'s fear in v. 7 is the rational response to this intelligence.</p>',
    "7": '<p><strong>וַיִּירָא יַעֲקֹב מְאֹד וַיֵּצֶר לוֹ</strong> (<em>wayyîrāʾ yaʿăqōḇ mĕʾōḏ wayyēṣer lô</em>) — "Jacob feared greatly and was distressed." The double emotional expression: <em>yārēʾ</em> (to fear — the existential recognition of threat) + <em>yāṣar</em> (to be narrow, distressed — literally "he was cramped/confined," the claustrophobic experience of being trapped with no way out). Both verbs together describe the complete paralysis of terror. <strong>וַיַּחַץ אֶת-הָעָם</strong> (<em>wayyaḥaṣ ʾet-hāʿām</em>) — "he divided the people." <em>Ḥāṣāh</em> (to divide, halve — cf. the root of Mahanaim [two camps]: Jacob implements the two-camp strategy suggested by the double-camp of the angels). Strategy emerges from fear: the division of the group into two halves increases the chance that at least one half survives an attack.</p>',
    "8": '<p><strong>אִם-יָבוֹא עֵשָׂו אֶל-הַמַּחֲנֶה הָאַחַת וְהִכָּהוּ</strong> — "if Esau comes to one camp and attacks it." Jacob\'s military thinking: if one camp (<em>maḥăneh</em>) falls, the remaining camp (<em>maḥăneh</em> — same word as Mahanaim) escapes. The two-camp strategy is survival-oriented, not victory-oriented: Jacob is planning escape, not defense. The word <em>maḥăneh</em> (camp) appears four times in vv. 7-8, connecting the Mahanaim angel-encounter to Jacob\'s human response: the divine two-camp (v. 2) generates the human two-camp (vv. 7-8).</p>',
    "9": '<p><strong>וַיֹּאמֶר יַעֲקֹב אֱלֹהֵי אָבִי אַבְרָהָם וֵאלֹהֵי אָבִי יִצְחָק</strong> — "Jacob prayed: O God of my father Abraham and God of my father Isaac." Jacob\'s prayer (vv. 9-12) is the most developed intercessory prayer in the patriarchal narratives and a model of OT petition: (1) invocation of the covenant God by covenant relationship; (2) appeal to YHWH\'s own prior promise (v. 9b: "the LORD who said to me \'return\' "); (3) confession of unworthiness (v. 10); (4) rehearsal of the current situation (v. 10b: "I have become two camps"); (5) petition for deliverance (v. 11); (6) appeal to the covenant promise (v. 12). The structure anticipates the formal prayer patterns of the Psalms (complaint, confession, petition, trust).</p>',
    "10": '<p><strong>קָטֹנְתִּי מִכֹּל הַחֲסָדִים וּמִכָּל-הָאֱמֶת</strong> (<em>qāṭontî mikkōl haḥăsāḏîm ûmikkol-hāʾemet</em>) — "I am unworthy of all the ḥeseḏ and all the faithfulness." <em>Qāṭan</em> (to be small, too little — in the Qal perfect: I have become small, I count myself small; cf. 1 Sam 15:17: "when you were small in your own eyes"). Jacob\'s confession of smallness before divine generosity is the opposite of his earlier self-assertion (ch. 27: he claimed Esau\'s identity; ch. 30: he negotiated shrewdly for the livestock; ch. 31: he argued his legal case confidently). Here, faced with his brother and his past, he is small. <strong>כִּי בְמַקְלִי עָבַרְתִּי</strong> (for with only my staff I crossed) — the staff (<em>maqqēl</em>) is the possession of the empty-handed traveler; Jacob departed from Canaan with only a walking stick; he returns with two camps.</p>',
    "11": '<p><strong>הַצִּילֵנִי נָא מִיַּד אָחִי מִיַּד עֵשָׂו</strong> (<em>haṣṣîlēnî nāʾ miyyaḏ ʾāḥî miyyaḏ ʿēśāw</em>) — "deliver me, please, from the hand of my brother, from the hand of Esau." The doubled petition — "from the hand of my brother" then "from the hand of Esau" — names both the relational (<em>ʾāḥ</em>, brother) and the personal (Esau) identity of the threat. The doubling emphasizes the relational tragedy: it is his <em>brother</em> from whom Jacob needs deliverance. <em>Kî yārēʾ ʾānōḵî ʾōtô</em> (for I am afraid of him) — the same fear-verb as v. 7; Jacob brings his fear directly to God as the content of the prayer, not as an embarrassment to confess away.</p>',
    "12": '<p><strong>וְאַתָּה אָמַרְתָּ הֵיטֵב אֵיטִיב עִמָּךְ</strong> (<em>wĕʾattāh ʾāmartā hêṭēḇ ʾêṭîḇ ʿimmāḵ</em>) — "and you said, I will surely do you good." The emphatic infinitive absolute <em>hêṭēḇ ʾêṭîḇ</em> (I will surely do good) — the unconditional divine promise cited as the basis of the petition: YHWH made a promise; Jacob appeals to it. <em>Wĕśamtî ʾet-zarʿĕḵā kĕḥôl hayyām</em> (and I will make your offspring like the sand of the sea) — the covenant promise of 22:17 and 28:14; Jacob quotes God\'s word back to God as the ground for his request. The prayer moves from confession of smallness to citation of divine promise: the two poles of OT petition.</p>',
    "13": '<p>Jacob spends the night after the prayer. The narrative pause between prayer (v. 9-12) and gift-selection (v. 13-21) is theologically significant: Jacob prays first, then acts. The order signals that the diplomatic strategy of vv. 13-21 is undertaken after and in the context of prayer — it is not a substitute for prayer but a complement to it. The gift-selection is Jacob\'s human response alongside YHWH\'s expected divine response.</p>',
    "14": '<p>The gift catalogue: 200 female goats, 20 male goats, 200 ewes, 20 rams. The ratios (10:1 female to male) reflect standard ANE flock proportions for productive breeding — the females are the productive units; the males are the minimal breeding complement. Jacob is giving Esau productive, breeding-capable livestock, not just culled animals. The total gift is substantial: 530 animals plus donkeys and camels (vv. 15), approaching the inventory of a wealthy man\'s flock.</p>',
    "15": '<p>The full gift: 30 nursing camels with foals, 40 cows, 10 bulls, 20 female donkeys, 10 male donkeys. The inclusion of nursing camels (<em>gĕmallîm mêyniqôt</em>, nursing camels with their young) shows the thoughtfulness of the gift: these are productive animals with their next generation already present. The total gift spans all the livestock categories Jacob catalogued to Esau\'s messengers (v. 5: cattle, donkeys, sheep, goats) — a comprehensive representation of his wealth.</p>',
    "16": '<p><strong>עֵדֶר עֵדֶר לְבַדּוֹ</strong> (<em>ʿēḏer ʿēḏer lĕḇaddô</em>) — "each herd by itself." The gifts are not sent as one mass but in separate droves with space between them. The spatial arrangement is tactical: each drove arrives separately with its own messenger speaking the same prepared message (vv. 17-19). The effect is a series of encounters: Esau meets one drove, then another, then another — each time receiving the same submissive message ("they are a gift sent to my lord Esau"). The repeated encounters are designed to soften Esau\'s anger through progressive reconciliation before Jacob himself appears.</p>',
    "17": '<p><strong>כִּי-יִפְגָּשְׁךָ עֵשָׂו אָחִי וּשְׁאֵלְךָ לֵאמֹר לְמִי-אַתָּה</strong> — "when Esau my brother meets you and asks \'to whom do you belong...?\'" The question Esau will ask is the standard challenge-question for a traveling group (<em>lĕmî-ʾattāh</em>, whose are you/what group do you belong to). Jacob prepares his servants with exact scripted answers — the preparation of speech for a diplomatic encounter mirrors the preparation of speech in ch. 24 (the servant\'s prayer and sign-request). Both chapters involve carefully planned speech before a decisive meeting.</p>',
    "18": '<p><strong>מִנְחָה הִיא שְׁלוּחָה לַאדֹנִי לְעֵשָׂו</strong> (<em>minḥāh hîʾ šĕlûḥāh laʾḏōnî lĕʿēśāw</em>) — "it is a gift sent to my lord Esau." <em>Minḥāh</em> (gift, tribute, offering — the same word used for the grain offering in the Levitical system; in diplomatic contexts it is tribute from an inferior to a superior). Jacob sends a <em>minḥāh</em> to Esau — the language of tribute from a subordinate to a lord, consistent with his use of <em>ʾăḏōnî</em> (my lord) throughout the message.</p>',
    "19": '<p>The three separate droves carry the same message, delivered by separate servants. The repetition is strategic: Jacob has scripted a consistent story and coached all his servants to deliver it identically. The scripted approach is the opposite of the Laban confrontation, where Jacob\'s speech was spontaneous legal defense. Here everything is planned, controlled, and aimed at one goal: preventing Esau\'s anger from becoming violence.</p>',
    "20": '<p><strong>כִּי-אֲכַפְּרָה פָנָיו בַּמִּנְחָה הַהֹלֶכֶת לְפָנָי</strong> (<em>kî-ʾăḵappĕrāh pānāyw bamminhāh hahōleket lĕpānay</em>) — "I will pacify/cover his face with the gift going before me." <em>Kipper</em> (Piel of <em>kāpar</em>, to cover, atone, appease — the word used throughout Leviticus for the atonement of sin; <em>yôm hakkippurîm</em>, Day of Atonement). Jacob uses the atonement vocabulary: he will "kipper" Esau\'s face — appease, cover over, propitiate — with gifts. The secular use of <em>kipper</em> for human-to-human appeasement shows that the word\'s core meaning is to "cover/wipe away" hostility through compensatory action, whether between humans or between humans and God. <em>ʾĂḵappĕrāh pānāyw</em> = "cover his face" — the face (<em>pānîm</em>) that bears the expression of hostility will be covered (its hostility wiped away) by the gift.</p>',
    "21": '<p><strong>וַתַּעֲבֹר הַמִּנְחָה עַל-פָּנָיו</strong> (<em>wattaʿăḇōr hamminḥāh ʿal-pānāyw</em>) — "the gift passed before him." The gifts go on ahead; Jacob remains in the camp. The word <em>ʾal-pānāyw</em> (before his face) — the gift is literally going "before Esau\'s face" to prepare the way; the gift-going-before is a form of advance diplomacy. <em>Wĕhûʾ lān ballayĕlāh hahûʾ</em> (he himself spent the night in the camp that night) — Jacob is alone with his plan and his fear before the morning encounter. The next verse will interrupt his night with the wrestling encounter.</p>',
    "22": '<p><strong>וַיָּקָם בַּלַּיְלָה הוּא וַיִּקַּח אֶת-שְׁתֵּי נָשָׁיו</strong> — "he rose in the night and took his two wives." Jacob\'s nocturnal action: he rises during the night and sends his family across the Jabbok ford. The sequence is precise: wives → female servants → eleven children → all possessions. <em>ʾēt maʿăḇar yaḇḇōq</em> (the ford of the Jabbok) — <em>Yabbōq</em> is the modern Zarqa river, the northern tributary of the Jordan in Transjordan. The name <em>yaḇḇōq</em> begins with the same three consonants as <em>yaʿăqōḇ</em> (Jacob) — the place name and the person name echo each other in the consonantal text. The wrestling of Jacob (<em>yaʿqōḇ</em>) at the Jabbok (<em>yaḇḇōq</em>) using the verb "wrestle" (<em>yēʾābēq</em>) creates a triple wordplay: yod-ayin-qoph / yod-beth-qoph / yod-aleph-beth-qoph.</p>',
    "23": '<p>Jacob sends all his possessions across the ford — the total evacuation of his camp to the other side of the Jabbok. After this verse, Jacob is entirely alone (v. 24: "Jacob was left alone"). The deliberate stripping away of all family, servants, and goods is Jacob\'s self-exposure: he crosses over nothing, he has sent everything ahead. The physical aloneness precedes the spiritual encounter.</p>',
    "24": '<p><strong>וַיִּוָּתֵר יַעֲקֹב לְבַדּוֹ</strong> (<em>wayyiwwātēr yaʿăqōḇ lĕḇaddô</em>) — "Jacob was left alone." <em>Yāthar</em> (Niphal: to be left over, to remain — what remains after everything else has gone). Jacob is the remainder: the last one left behind on his side of the ford. <strong>וַיֵּאָבֵק אִישׁ עִמּוֹ עַד עֲלוֹת הַשָּׁחַר</strong> (<em>wayyēʾābēq ʾîš ʿimmô ʿaḏ ʿălôt haššāḥar</em>) — "and a man wrestled with him until the breaking of the dawn." <em>ʾĀḇaq</em> (to wrestle/grapple — a hapax in this form; possibly from <em>ʾāḇāq</em>, dust, suggesting rolling in the dust of a wrestling match; or related to a root meaning to clasp, hold). The wrestling partner is identified as <em>ʾîš</em> (a man) — not "angel," not "God" — but the identity is deliberately ambiguous. The narrative withholds the identity; only Jacob\'s interpretation in v. 30 ("I have seen God face to face") and Hosea\'s retroactive identification (Hos 12:4: "he strove with an angel") name the wrestler after the fact.</p>',
    "25": '<p><strong>כִּי לֹא יָכֹל לוֹ</strong> (<em>kî lōʾ yāḵōl lô</em>) — "when he saw that he could not prevail against him." The wrestler (<em>ʾîš</em>) is unable to overpower Jacob — the one who claims to be divine (or is) is stalemate against the human. <strong>וַיִּגַּע בְּכַף-יְרֵכוֹ</strong> (<em>wayyiggaʿ bĕḵap-yĕrēḵô</em>) — "he touched the socket of Jacob\'s hip." <em>Nāgaʿ</em> (to touch — often of divine touch with transformative effect: Isa 6:7 where the seraph touches Isaiah\'s lips; Jer 1:9 where YHWH touches Jeremiah\'s mouth; Dan 10:16, 18). The divine touch on the hip-socket (<em>kap-yāreḵ</em>, the hollow/socket of the thigh joint) dislocates it: <em>watteqaʿ kap-yereḵ yaʿăqōḇ bĕhēʾāḇqô ʿimmô</em> (the socket of Jacob\'s hip was wrenched as he wrestled). <em>Yāreḵ</em> is the same word as the oath-thigh of 24:2 and 47:29 — the seat of generative power and oath; here it is the point of divine touch and permanent alteration.</p>',
    "26": '<p><strong>שַׁלְּחֵנִי כִּי עָלָה הַשָּׁחַר</strong> (<em>šallĕḥēnî kî ʿālāh haššāḥar</em>) — "let me go, for the dawn is breaking." <em>Šālaḥ</em> (to send away, release, let go) — the send-verb that runs through the patriarchal narratives; now Jacob is the one asked to release. The dawn-deadline (<em>kî ʿālāh haššāḥar</em>) is an urgency that has no plain explanation: why must the wrestling end at dawn? Various interpretations: (1) divine beings cannot be seen in daylight; (2) the dawn breaks the theophanic night; (3) the impending day of meeting Esau makes the night\'s encounter a preparation that must conclude. <strong>לֹא אֲשַׁלֵּחֲךָ כִּי אִם-בֵּרַכְתָּנִי</strong> (I will not let you go unless you bless me) — Jacob\'s reply is pure Jacob: he turns the wrestling into a blessing-extraction. From the moment he grabbed Esau\'s heel at birth to the stolen blessing of ch. 27, Jacob grasps; now he grasps the divine wrestler for blessing. The irony is that the blessing he extracted through deception from Isaac he now seeks legitimately through struggle with God.</p>',
    "27": '<p><strong>מַה-שְּׁמֶךָ</strong> (<em>mah-šĕmeḵā</em>) — "what is your name?" The question reverses the pattern of ch. 27: Isaac asked "who are you, my son?" and Jacob answered falsely ("I am Esau"). Now the divine wrestler asks "what is your name?" and Jacob answers truly: <em>yaʿăqōḇ</em> (Jacob). The name-question in the OT often precedes a name-change (Abram → Abraham, 17:5). The answer "Jacob" is simultaneously a self-identification and a confession: the supplanter, the heel-grabber, the deceiver — this is who I am. Saying the name truthfully to God may be the first step of the transformation that follows.</p>',
    "28": '<p><strong>לֹא יַעֲקֹב יֵאָמֵר שִׁמְךָ כִּי אִם-יִשְׂרָאֵל</strong> (<em>lōʾ yaʿăqōḇ yēʾāmer šĕmeḵā kî ʾim-yiśrāʾēl</em>) — "your name shall no longer be Jacob but Israel." The name-change as covenant moment — Abraham (17:5), Sarah (17:15), and now Jacob. <em>Yiśrāʾēl</em> — etymology in the text: <em>kî-śārîtā ʿim-ʾĔlōhîm wĕʿim-ʾănāšîm wattûḵal</em> (for you have striven with God and with humans and have prevailed). <em>Śārîtā</em> (you have striven/persisted — Qal of <em>śārāh</em>, to persist, exert oneself, strive; possibly related to <em>śar</em>, prince — giving the alternate reading "for you have been a prince with God"). The name Israel = <em>yiśrā</em> (from <em>śārāh</em>) + <em>ʾēl</em> (God) = "he who strives with God" or "God strives/prevails." The wrestling is not Jacob\'s defeat but his prevailing — <em>wattûḵal</em> (and you have prevailed): Jacob won the wrestling match in some sense, receiving the blessing he demanded.</p>',
    "29": '<p><strong>הַגִּידָה-נָּא שְׁמֶךָ</strong> (<em>haggîḏāh-nnāʾ šĕmeḵā</em>) — "tell me your name, please." Jacob asks the wrestler\'s name — a request the wrestler refuses: <em>lāmmāh zeh tišʾal lišmî</em> (why do you ask my name?). The divine refusal to reveal a name is a consistent pattern: in Exod 3:14 YHWH gives "I AM WHO I AM" — not a proper name but a self-referential formula; in Judg 13:18 the angel tells Manoah "why do you ask my name? It is wonderful/beyond understanding" (<em>wĕhûʾ-pelîʾî</em>). The name of God is not a formula that can be possessed and used; it remains in divine sovereignty. Yet the one who refuses to give his name gives his blessing: <em>wayyĕḇāreḵ ʾōtô šām</em> (he blessed him there). The blessing without the name is itself the covenant: YHWH acts without being controlled by the one who knows his name.</p>',
    "30": '<p><strong>וַיִּקְרָא יַעֲקֹב שֵׁם הַמָּקוֹם פְּנִיאֵל</strong> (<em>wayyiqrāʾ yaʿăqōḇ šēm hammāqôm pĕnîʾēl</em>) — "Jacob called the name of the place Peniel." <em>Pĕnîʾēl</em> = "face of God" (<em>pāneh</em> + <em>ʾēl</em>); the place is named from Jacob\'s experience: <strong>כִּי-רָאִיתִי אֱלֹהִים פָּנִים אֶל-פָּנִים</strong> (for I have seen God face to face). <em>Pānîm ʾel-pānîm</em> (face to face) — the same expression used for Moses\' intimacy with YHWH (Exod 33:11: "YHWH spoke to Moses face to face as a man speaks to his friend"; Deut 34:10: "Moses whom YHWH knew face to face"). Jacob\'s face-to-face encounter with God is the patriarchal precedent for the intimacy that will be named most fully in Moses. <strong>וַתִּנָּצֵל נַפְשִׁי</strong> (yet my life has been delivered/spared) — the standard formula for surviving a divine encounter that was expected to be fatal (cf. Isa 6:5: "I am undone, for I have seen the King, YHWH of armies"; Judg 13:22: "we shall surely die, for we have seen God").</p>',
    "31": '<p><strong>וַיִּזְרַח-לוֹ הַשֶּׁמֶשׁ כַּאֲשֶׁר עָבַר אֶת-פְּנוּאֵל</strong> (<em>wayyizraḥ-lô haššemeš kaʾăšer ʿāḇar ʾet-pĕnûʾēl</em>) — "the sun rose upon him as he passed Penuel." The sun-rising is both chronological (dawn, as anticipated in v. 26) and symbolic: Jacob wrestled in darkness and emerges into light. The play on the name Peniel/Penuel (variant spellings) — "face of God" — and the rising sun creates a visual of light where the face of God was. <em>Wĕhûʾ ṣōlēaʿ ʿal-yĕrēḵô</em> (he was limping because of his hip) — the limp is the permanent physical mark of the divine encounter. Jacob walks differently after Peniel: every step for the rest of his life is a reminder of the night he wrestled with God. The blessing and the wound come together from the same encounter.</p>',
    "32": '<p><strong>עַל-כֵּן לֹא-יֹאכְלוּ בְנֵי-יִשְׂרָאֵל אֶת-גִּיד הַנָּשֶׁה</strong> (<em>ʿal-kēn lōʾ-yōʾḵĕlû ḇĕnê-yiśrāʾēl ʾet-gîḏ hannāšeh</em>) — "therefore the children of Israel do not eat the tendon of the hip socket." The etiological formula <em>ʿal-kēn</em> (therefore, on account of this) closes the Peniel episode with an explanation for a continuing Israelite dietary practice: abstaining from the sciatic nerve (<em>gîd hannāšeh</em>, the sinew of the hollow — possibly the sciatic nerve or the adjacent connective tissue). <em>Gîḏ hannāšeh</em> (<em>gîḏ</em> = sinew, tendon; <em>nāšeh</em> = displaced, moved out of joint — the tendon that moves/is displaced at the joint) — the prohibition is not in the Mosaic law directly but is attested in the Talmud as a halakhic practice derived from this narrative. The closing etiology grounds the community\'s embodied practice in the patriarchal narrative: every observant Israelite\'s eating practice is a living memorial to Jacob\'s night at the Jabbok.</p>'
  }
}

def main():
    existing = load_comm('mkt-original', 'genesis')
    merge_comm(existing, GENESIS)
    save_comm('mkt-original', 'genesis', existing)
    print('Genesis 31-32 mkt-original written.')

if __name__ == '__main__':
    main()
